import { Component, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { Router, RouterLink, ActivatedRoute } from '@angular/router';
import { toSignal } from '@angular/core/rxjs-interop';
import { AuthService } from '../../core/services/auth.service';
import { SiteviewService } from '../../core/services/siteview.service';

@Component({
  selector: 'app-projects-list',
  standalone: true,
  imports: [CommonModule, FormsModule, RouterLink],
  templateUrl: './projects-list.component.html',
  styleUrl: './projects-list.component.css',
})
export class ProjectsListComponent {
  private readonly qp = toSignal(this.route.queryParamMap, { requireSync: true });

  readonly projects = this.sv.projects;
  readonly loading = signal(false);

  readonly modalOpen = computed(() => this.qp().get('modal') === 'project');
  readonly editId = computed(() => this.qp().get('id'));
  draftName = '';

  constructor(
    public auth: AuthService,
    private sv: SiteviewService,
    private router: Router,
    private route: ActivatedRoute,
  ) {}

  phaseCount(projectId: string): number {
    return this.sv.phasesForProject(projectId).length;
  }
  taskCount(projectId: string): number {
    return this.sv.tasksForProject(projectId).length;
  }
  hazardCount(projectId: string): number {
    return this.sv.getDashboard(projectId).openHazards;
  }

  openCreate(): void {
    this.draftName = '';
    this.router.navigate([], { queryParams: { modal: 'project' }, queryParamsHandling: 'merge' });
  }

  openEdit(id: string, name: string, ev: Event): void {
    ev.stopPropagation();
    ev.preventDefault();
    this.draftName = name;
    this.router.navigate([], { queryParams: { modal: 'project', id }, queryParamsHandling: 'merge' });
  }

  closeModal(): void {
    this.router.navigate([], { queryParams: { modal: null, id: null }, queryParamsHandling: 'merge' });
  }

  save(): void {
    const name = this.draftName.trim();
    if (!name) return;
    const id = this.editId();
    if (id) this.sv.updateProject(id, name);
    else this.sv.createProject(name);
    this.closeModal();
  }

  remove(id: string, ev: Event): void {
    ev.stopPropagation();
    ev.preventDefault();
    this.sv.deleteProject(id);
  }

  // keep draftName synced when opening edit modal via deep-link
  syncDraft(): void {
    const id = this.editId();
    if (id && !this.draftName) {
      this.draftName = this.sv.getProject(id)?.name ?? '';
    }
  }
}
